void main() {
    vec2 uv = gl_FragCoord.xy / u_resolution.xy;
    vec2 cp = uv * 2.0 - 1.0;
    cp.x *= u_resolution.x / u_resolution.y; // Aspect ratio correction

    float time_slow = u_time * 0.03; // Very slow animation

    vec2 warped_cp = cp; // Start with original coordinates for warping

    // Multi-layered sine warp with progressively decreasing frequencies and amplitudes
    // Layer 1: Highest frequency, highest amplitude
    float freq1 = 16.0;
    float amp1 = 0.08;
    warped_cp.x += sin(warped_cp.y * freq1 + time_slow * 1.0) * amp1;
    warped_cp.y += cos(warped_cp.x * freq1 * 0.8 + time_slow * 0.7) * amp1 * 0.8;

    // Layer 2: Medium frequency, medium amplitude
    float freq2 = 12.0;
    float amp2 = 0.05;
    warped_cp.x += sin(warped_cp.y * freq2 + time_slow * 1.2) * amp2;
    warped_cp.y += cos(warped_cp.x * freq2 * 0.9 + time_slow * 0.7)) * amp2 * 0.9;

    // Layer 3: Lowest frequency, lowest amplitude
    float freq3 =  8.0;
    float amp3 = 0.03;
    warped_cp.x += sin(warped_cp.y * freq3 + time_slow * 1.4) * amp3;
    warped_cp.y += cos(warped_cp.x * freq3 * 1.1 + time_slow * 0.9) * amp3 * 1.1;

    // Calculate base undulating value
    // Use a combination of x and y for more organic undulations
    float value = sin(warped_cp.y * 6.0 + warped_cp.x * 2.0 + time_slow * 0.5) * 0.5 + 0.5;

    // Smoothstep-based damping across the canvas
    float dist_center = length(cp); // Use the original 'cp' for consistent damping
