    // Novel 'quantum entanglement' feedback system: mutually warp coordinate spaces
    // Interaction strength governed by Simplex noise and damped by radial falloff
    p_a += wave_b * noise_strength * 0.15 * warp_damping;
    p_b += wave_a * noise_strength * 0.15 * warp_damping;

    // Generate patterns from the warped coordinates
    float pattern_a = sin(length(p_a * 10.0 + u_time * 0.2) + u_time * 0.1);
    float pattern_b = cos(length(p_b * 12.0 + u_time * 0.25) - u_time * 0.08);

    // Combine patterns, normalize to [0, 1] for color mapping
    float final_pattern = (pattern_a + pattern_b);
    final_pattern = (final_pattern + 2.0) * 0.25; // Map theoretical [-2, 2] to [0, 1]

    // Deep, subtle color shifts
    vec3 base_color = vec3(0.05, 0.1, 0.25); // Dark blue-purple base
    vec3 accent_color = vec3(0.5, 0.25, 0.1); // Muted orange-red accent

