    float color_mix_factor = final_pattern + sin(u_time * 0.04 + dist * 3.0) * 0.1;
    color_mix_factor = clamp(color_mix_factor, 0.0, 1.0);
    vec3 col = mix(base_color, accent_color, color_mix_factor);

