    float wave_val = sin(ar_uv.x * 10.0 + u_time * 0.5) * cos(ar_uv.y * 10.0 - u_time * 0.3);

    // Introduce a secondary, lower frequency pattern for organic flow
    float flow_val = noise(ar_uv * 3.0 + u_time * 0.1) * 0.5 + noise(ar_uv * 5.0 - u_time * 0.08) * 0.3;

    // Combine these, then apply the anticipatory damping.
    // The damping_influence reduces the overall intensity of the pattern
    // when the system is changing rapidly (dE_dt_local is high).
    // This makes the pattern "calm down" when it's too active.
    float final_pattern = (wave_val + flow_val) * (1.0 - damping_influence * 0.8); // 0.8 to not fully dampen

    // Add a base noise for subtle texture and ensure some activity even when damped
    float base_noise = noise(ar_uv * 15.0 + u_time * 0.02) * 0.1;

    float color_component = fract(final_pattern * 0.5 + E_t * 0.3 + base_noise);

    // Smoothstep for a soft, tranquil color mapping
    vec3 color = vec3(
        smoothstep(0.0, 1.0, color_component + 0.1),
        smoothstep(0.0, 1.0, color_component * 0.8 + 0.2),
        smoothstep(0.0, 1.0, color_component * 0.6 + 0.3)
    );

    // Subtle color shift based on mouse for interaction
    vec3 mouse_color_shift = vec3(u_mouse.x / u_resolution.x, u_mouse.y / u_resolution.y, 0.5);
    color = mix(color, mouse_color_shift, 0.05); // Very subtle influence

    // Final output color, enhanced for tranquility
    gl_FragColor = vec4(color * (0.8 + E_t * 0.2), 1.0); // E_t adds a slight brightness modulation
}

precision mediump float;

uniform float u_time;
uniform vec2 u_resolution;
