// Hash function for random-like values
float hash11(float p) {
    p = fract(p * .1031);
    p *= p + 33.33;
    p = p * p + p;
    return fract(p);
}

// 2D Noise function (Simplex-like, for subtle variations)
vec2 hash22(vec2 p) {
    p = fract(p * vec2(5.3983, 5.4427));
    p += dot(p.yx, p.xy + vec2(21.5351, 14.3137));
    return fract(vec2(p.x * p.y, p.x + p.y));
}

float noise(vec2 p) {
    vec2 ip = floor(p);
    vec2 fp = fract(p);
    fp = fp * fp * (3.0 - 2.0 * fp); // Smoothstep

    vec2 h0 = hash22(ip);
    vec2 h1 = hash22(ip + vec2(1.0, 0.0));
    vec2 h2 = hash22(ip + vec2(0.0, 1.0));
    vec2 h3 = hash22(ip + vec2(1.0, 1.0));

    float res = mix(mix(dot(h0, fp - vec2(0.0, 0.0)), dot(h1, fp - vec2(1.0, 0.0)), fp.x),
                    mix(dot(h2, fp - vec2(0.0, 1.0)), dot(h3, fp - vec2(1.0, 1.0)), fp.x), fp.y);
    return res * 0.5 + 0.5; // Scale to [0, 1]
}

// Function to calculate the gradient of a scalar field (approximate d/dx)
vec2 gradient(vec2 p, float val_func(vec2), float eps) {
    float v = val_func(p);
    float vx = val_func(p + vec2(eps, 0.0));
    float vy = val_func(p + vec2(0.0, eps));
    return normalize(vec2(vx - v, vy - v));
}

void main() {
    vec2 uv = gl_FragCoord.xy / u_resolution.xy;
    uv.x *= u_resolution.x / u_resolution.y; // Aspect correction
    vec2 center = vec2(0.5 * u_resolution.x / u_resolution.y, 0.5);

    vec2 p = uv * 2.0 - center * 2.0; // Centered coordinates

    float time = u_time * 0.1;

    // Base wave driver
    float base_freq = 1.0;
    float base_amp = 0.5;
    float base_wave = sin(p.x * base_freq + time * 1.5) * cos(p.y * base_freq * 0.8 + time * 1.2);

    // Iterative feedback loop for emergent wave
    vec2 current_pos = p;
    float total_energy = 0.0;
    float damping_factor = 0.9;
    float phase_shift = 0.0;

    for (int i = 0; i < 5; ++i) {
        float f_i = float(i);

        // Propagating wave amplitude (E)
        float wave_E = sin(dot(current_pos, vec2(1.0, 0.8) + hash22(current_pos * 0.1 + f_i)) * (2.0 + f_i * 0.5) + time * (1.0 + f_i * 0.3));
        wave_E += cos(dot(current_pos, vec2(0.7, 1.2) + hash22(current_pos * 0.2 + f_i)) * (1.5 + f_i * 0.4) + time * (1.2 + f_i * 0.2));
        wave_E *= 0.5; // Normalize to [-0.5, 0.5]

        // Approximate spatial gradient (d/dx) of wave_E
        // We need to pass a function to gradient, so let's define a simple lambda-like helper here
        // This is a common pattern to approximate a function's gradient.
        float dx_eps = 0.005;
        vec2 grad_E_approx = normalize(vec2(
            (sin(dot(current_pos + vec2(dx_eps, 0.0), vec2(1.0, 0.8) + hash22(current_pos * 0.1 + f_i)) * (2.0 + f_i * 0.5) + time * (1.0 + f_i * 0.3)) + 
             cos(dot(current_pos + vec2(dx_eps, 0.0), vec2(0.7, 1.2) + hash22(current_pos * 0.2 + f_i)) * (1.5 + f_i * 0.4) + time * (1.2 + f_i * 0.2))) * 0.5 - wave_E,
            (sin(dot(current_pos + vec2(0.0, dx_eps), vec2(1.0, 0.8) + hash22(current_pos * 0.1 + f_i)) * (2.0 + f_i * 0.5) + time * (1.0 + f_i * 0.3)) + 
             cos(dot(current_pos + vec2(0.0, dx_eps), vec2(0.7, 1.2) + hash22(current_pos * 0.2 + f_i)) * (1.5 + f_i * 0.4) + time * (1.2 + f_i * 0.2))) * 0.5 - wave_E
        ));

        // Dynamic frequency modulation (P_mod) based on spatial gradient magnitude
        // The magnitude of the gradient influences the local frequency of the harmonic driver
        float P_mod_freq = 1.0 + length(grad_E_approx) * 3.0; // Scale gradient to influence frequency

        // Harmonic driver with self-tuning frequency
        float harmonic_driver = sin(dot(current_pos, grad_E_approx * P_mod_freq) * 3.0 + time * 0.8 + phase_shift);

        // Feedback: influence current_pos based on wave_E and harmonic_driver
        current_pos += grad_E_approx * (wave_E + harmonic_driver) * (0.01 + 0.005 * f_i) * damping_factor;

        // Accumulate energy
        total_energy += abs(wave_E) * damping_factor;

        // Update damping and phase for next iteration
        damping_factor *= 0.7;
        phase_shift += harmonic_driver * 0.5; // Accumulate phase based on harmonic driver

        // Add subtle noise for organic variation
        current_pos += (noise(current_pos * 5.0 + time * 0.5) - 0.5) * 0.01;
    }

    // Final color based on accumulated energy and subtle base wave
    float final_value = (total_energy * 0.3 + base_wave * 0.1);
    final_value = pow(final_value, 2.0); // Enhance contrast
    final_value += noise(p * 10.0 + time * 2.0) * 0.05; // High-frequency detail

    // Soft color mapping
    vec3 color = vec3(0.0);
    color = mix(vec3(0.05, 0.1, 0.15), vec3(0.15, 0.3, 0.4), final_value * 1.5);
    color = mix(color, vec3(0.8, 0.9, 1.0), pow(final_value, 4.0)); // Brighter highlights

    // Vignette
    float len_p = length(p / vec2(u_resolution.x / u_resolution.y, 1.0));
    color *= smoothstep(1.5, 0.5, len_p);

    gl_FragColor = vec4(color, 1.0);
}

precision mediump float;

uniform float u_time;
