// Hash function for random values
float hash(vec2 p) {
    p = fract(p * 0.3183099 + vec2(0.1));
    p *= p + 0.19105946;
    return fract(p.x*p.y);
}

// 2D Simplex Noise (from Ashima Arts, modified for GLSL ES 1.0)
vec3 mod289(vec3 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
vec2 mod289(vec2 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
vec3 permute(vec3 x) { return mod289(((x*34.0)+1.0)*x); }
float snoise(vec2 v) {
    const vec4 C = vec4(0.211324865405187, 0.366025403784439, -0.577350269189626, 0.024390243902439);
    vec2 i = floor(v + dot(v, C.yy));
    vec2 x0 = v - i + dot(i, C.xx);
    vec2 i1;
    i1 = (x0.x > x0.y) ? vec2(1.0, 0.0) : vec2(0.0, 1.0);
    vec4 x12 = x0.xyxy + C.xxzz;
    x12.x += i1.x;
    x12.y += i1.y;
    x12.z += 1.0;
    x12.w += 1.0;
    i = mod289(i);
    vec3 p = permute(permute(i.y + vec3(0.0, i1.y, 1.0 )) + i.x + vec3(0.0, i1.x, 1.0 ));
    vec3 m = max(0.5 - vec3(dot(x0,x0), dot(x12.xy,x12.xy), dot(x12.zw,x12.zw)), 0.0);
    m = m*m;
    m = m*m;
    vec3 x = 2.0 * fract(p * C.www) - 1.0;
    vec3 h = abs(x) - 0.5;
    vec3 ox = floor(x + 0.5);
    vec3 a0 = x - ox;
    m *= 1.79284291400159 - 0.85373472095314 * ( a0*a0 + h*h );
    vec3 g;
    g.x  = a0.x  * x0.x  + h.x  * x0.y;
    g.y  = a0.y  * x12.x + h.y  * x12.y;
    g.z  = a0.z  * x12.z + h.z  * x12.w;
    return 130.0 * dot(m, g);
}


// Function to simulate a localized 'emergent state' E
// This could be a complex pattern derived from noise, waves, and feedback.
float getEmergentState(vec2 uv, float t) {
    float n1 = snoise(uv * 3.0 + vec2(t * 0.1, t * 0.05));
    float n2 = snoise(uv * 7.0 - vec2(t * 0.08, t * 0.12));
    float n3 = snoise(uv * 12.0 + vec2(t * 0.03, t * 0.09));

    // Combine noise layers, add some wave-like motion
    float E = (n1 + n2 * 0.5 + n3 * 0.25);
    E += sin(dot(uv, vec2(10.0, 7.0)) + t * 0.5) * 0.3;
    E = fract(E * 0.5 + 0.5); // Normalize to [0,1] and make it more "fluid"
    return E;
}

void main() {
    vec2 uv = gl_FragCoord.xy / u_resolution.xy;
    uv.x *= u_resolution.x / u_resolution.y; // Aspect ratio correction

    float t = u_time * 0.2;

    // --- Core Systemic Intelligence: (d/dt)E -> P_mod ---

    // 1. Calculate current emergent state E(t)
    float E_current = getEmergentState(uv, t);

    // 2. Predict future emergent state E(t + dt)
    // Use a small time step for the derivative approximation
    float dt = 0.01; 
    float E_future = getEmergentState(uv, t + dt);

    // 3. Approximate the rate of change (d/dt)E
    // This is the "predicted future divergence"
    float dE_dt = (E_future - E_current) / dt;

    // 4. Modulate localized feedback loop strength (P_mod) based on dE_dt
    // The hypothesis states P_mod increases proportionally to dE_dt to resist entropy.
    // We want P_mod to be higher when the pattern is changing rapidly,
    // implying it's diverging from a stable state or experiencing high "entropy".
    // This feedback should then "pull" the pattern back or reinforce its structure.
    float P_mod = abs(dE_dt) * 5.0; // Higher P_mod for higher divergence
    P_mod = clamp(P_mod, 0.1, 2.0); // Keep P_mod within a reasonable range

    // --- Apply P_mod to influence the final pattern ---

    // Use P_mod to adjust parameters of the pattern generation, 
    // simulating an anticipatory control mechanism.
    // For instance, P_mod can influence a "damping" factor or "intensity" of a layer.

    float base_pattern = snoise(uv * 2.0 + t * 0.05);

    // Re-evaluate E_current with P_mod influencing its internal dynamics.
    // This simulates the feedback loop: dE_dt -> P_mod -> E_new
    // We can use P_mod to subtly warp coordinates or adjust amplitudes.
    vec2 warped_uv = uv + vec2(snoise(uv * 5.0 + t * 0.1) * 0.05 * P_mod, 
                               snoise(uv * 6.0 - t * 0.07) * 0.05 * P_mod);

    float E_final = getEmergentState(warped_uv, t);

    // Introduce a secondary, more subtle layer influenced by P_mod
    // This layer can be seen as the system actively "sculpting" details
    // to counteract the divergence.
    float sculpting_layer = snoise(uv * 15.0 + t * 0.3 + E_final * 2.0);
    sculpting_layer = pow(abs(sculpting_layer), 2.0) * sign(sculpting_layer); // Sharpen
    sculpting_layer *= (1.0 - P_mod * 0.3); // Less sculpting when P_mod is high (more active stabilization)

    // Combine for final color
    float final_value = E_final * 0.7 + base_pattern * 0.3 + sculpting_layer * 0.1;

    // Smooth step for softer forms
    final_value = smoothstep(0.3, 0.7, final_value);

    // Apply a gentle color gradient
    vec3 color1 = vec3(0.05, 0.1, 0.2); // Deep blue
    vec3 color2 = vec3(0.3, 0.5, 0.7); // Mid blue
    vec3 color3 = vec3(0.8, 0.9, 0.95); // Light almost white

    vec3 final_color = mix(color1, color2, final_value);
    final_color = mix(final_color, color3, smoothstep(0.6, 1.0, final_value));

    // Subtle temporal modulation on color for living feel
    final_color += sin(u_time * 0.5 + uv.x * 3.0) * 0.03;

    gl_FragColor = vec4(final_color, 1.0);
}

precision mediump float;

uniform float u_time;
uniform vec2 u_resolution;
