// Helper function for 2D Simplex Noise
// Source: https://github.com/ashima/webgl-noise/blob/master/src/noise2D.glsl
vec3 mod289(vec3 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
vec2 mod289(vec2 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
vec3 permute(vec3 x) { return mod289(((x*34.0)+1.0)*x); }

float snoise(vec2 v) {
    const vec4 C = vec4(0.211324865405187, // (3.0-sqrt(3.0))/6.0
                        0.366025403784439, // 0.5*(sqrt(3.0)-1.0)
                       -0.577350269189626, // -1.0 + 2.0 * C.x
                        0.024390243902439); // 1.0 / 41.0
    vec2 i = floor(v + dot(v, C.yy));
    vec2 x0 = v - i + dot(i, C.xx);
    vec2 i0;
    i0 = (x0.x > x0.y) ? vec2(1.0, 0.0) : vec2(0.0, 1.0);
    vec2 x1 = x0.xy + C.xx - i0;
    vec2 x2 = x0.xy + C.zz;
    vec3 p = permute( permute( i.y + vec3(0.0, i0.y, 1.0 )) + i.x + vec3(0.0, i0.x, 1.0 ));
    vec3 m = max(0.5 - vec3(dot(x0,x0), dot(x1,x1), dot(x2,x2)), 0.0);
    m = m * m;
    m = m * m;
    vec3 x = 2.0 * fract(p * C.www) - 1.0;
    vec3 h = abs(x) - 0.5;
    vec3 ox = floor(x + 0.5);
    vec3 a0 = x - ox;
    m *= 1.79284291400159 - 0.85373472095314 * ( a0*a0 + h*h );
    vec3 g;
    g.x = a0.x * x0.x + h.x * x0.y;
    g.yz = a0.yz * vec2(x1.x,x2.x) + h.yz * vec2(x1.y,x2.y);
    return 130.0 * dot(m, g);
}

// Function to calculate a "pattern density" value at a given coordinate and time
// This incorporates a simple temporal feedback loop for density
float getPatternDensity(vec2 p, float t) {
    float n1 = snoise(p * 2.5 + vec2(0.0, t * 0.1));
    float n2 = snoise(p * 5.0 + vec2(t * 0.05, 0.0) + n1 * 0.5);
    float n3 = snoise(p * 10.0 + vec2(0.0, t * 0.02) + n2 * 0.3);
    return (n1 + n2 * 0.5 + n3 * 0.25) / 1.75; // Normalize to approx -1 to 1
}

// Function to estimate the temporal derivative of pattern density
// This is a simplified finite difference over a small time delta
float getDensityRateOfChange(vec2 p, float t, float dt) {
    float density_now = getPatternDensity(p, t);
    float density_prev = getPatternDensity(p, t - dt);
    return (density_now - density_prev) / dt;
}

void main() {
    vec2 uv = gl_FragCoord.xy / u_resolution.xy;
    uv.x *= u_resolution.x / u_resolution.y; // Aspect correction
    vec2 p = uv * 3.0 - vec2(1.5); // Scale and center for noise

    float time_delta = 0.05; // Small time step for derivative estimation

    // Calculate current pattern density
    float current_density = getPatternDensity(p, u_time);

    // Calculate rate of change of pattern density (d/dt)E
    float density_rate_of_change = getDensityRateOfChange(p, u_time, time_delta);

    // Map (d/dt)E to P_mod (boundary stiffness)
    // When density changes rapidly (high abs(d/dt)E), boundaries should be stiffer (higher P_mod)
    // When density changes slowly, boundaries should be softer (lower P_mod)
    // Scale density_rate_of_change to a reasonable range for modulation
    float p_mod_raw = abs(density_rate_of_change) * 0.5 + 0.1; // Base stiffness + dynamic part
    float p_mod = clamp(p_mod_raw, 0.2, 1.5); // Clamp P_mod to a reasonable range

    // Apply P_mod to influence the 'boundary' or 'edge' detection
    // A higher P_mod makes the 'boundary' sharper/stiffer
    float value = current_density;

    // Use a step-like function or a smoothed step to create boundaries
    // The 'stiffness' (p_mod) influences the steepness of the gradient or the threshold
    float threshold = 0.0;
    float softness = 0.1 / p_mod; // Higher P_mod -> smaller softness -> sharper boundary

    float boundary_strength = smoothstep(threshold - softness, threshold + softness, value);

    // Introduce a subtle temporal wobble for organic feel
    boundary_strength += snoise(p * 0.5 + u_time * 0.2) * 0.05;

    // Apply a second layer of noise for fine detail and organic texture
    float detail_noise = snoise(p * 20.0 + u_time * 0.01) * 0.1;
    detail_noise = pow(abs(detail_noise), 2.0) * sign(detail_noise); // Bias towards center

    float final_value = boundary_strength + detail_noise * (1.0 - boundary_strength);
    final_value = clamp(final_value, 0.0, 1.0);

    // Color mapping for a serene aesthetic
    vec3 color1 = vec3(0.1, 0.2, 0.3); // Dark blue-grey
    vec3 color2 = vec3(0.8, 0.9, 0.95); // Light almost white blue

    vec3 final_color = mix(color1, color2, final_value);

    gl_FragColor = vec4(final_color, 1.0);
}

precision mediump float;

uniform float u_time;
uniform vec2 u_resolution;
uniform vec2 u_mouse;

// Hash function for pseudo-random values
vec3 hash33(vec3 p) {
    p = fract(p * vec3(443.897, 441.427, 437.197));
    p += dot(p, p.yxz + 19.19);
    return fract(vec3(p.x * p.y, p.z * p.x, p.y * p.z));
}

// 3D Simplex noise from Inigo Quilez
float snoise(vec3 p) {
    vec3 ip = floor(p);
    vec3 fp = fract(p);
    vec3 r0 = fp;
    vec3 r1 = fp - 1.0;
    vec3 r2 = fp - 2.0;

    vec3 v0 = ip;
    vec3 v1 = ip + 1.0;
    vec3 v2 = ip + 2.0;

    vec3 h0 = hash33(v0);
    vec3 h1 = hash33(v1);
    vec3 h2 = hash33(v2);

    float n = dot(r0, h0) + dot(r1, h1) + dot(r2, h2);
    return n * 0.5 + 0.5; // Scale to [0, 1]
}

// Function to simulate pattern complexity or "energy"
// A simple metric based on local variance or gradient magnitude
float calculate_complexity(vec2 uv, float t) {
    float s = 0.005; // Sampling step
    float v0 = snoise(vec3(uv * 5.0, t * 0.1));
    float vx = snoise(vec3((uv + vec2(s, 0.0)) * 5.0, t * 0.1));
    float vy = snoise(vec3((uv + vec2(0.0, s)) * 5.0, t * 0.1));

    float dx = vx - v0;
    float dy = vy - v0;

    return sqrt(dx*dx + dy*dy); // Gradient magnitude as complexity proxy
}

void main() {
    vec2 uv = gl_FragCoord.xy / u_resolution.xy;
    uv.x *= u_resolution.x / u_resolution.y; // Aspect ratio correction

    float time = u_time * 0.1;

    // --- Step 1: Calculate current pattern complexity (E) ---
    float current_E = calculate_complexity(uv, time);

    // --- Step 2: Calculate past pattern complexity (E_prev) ---
    // This requires sampling a slightly older state.
    // For a fragment shader, we can simulate this by sampling a slightly earlier 'time'
    // or by averaging across a small temporal window.
    // Here, we'll use a direct earlier time sample for simplicity and conceptual clarity.
    float delta_t_sample = 0.1; // Small time step for derivative approximation
    float prev_E = calculate_complexity(uv, time - delta_t_sample);

    // --- Step 3: Estimate rate-of-change of complexity (d/dt)E ---
    // Simple finite difference approximation
    float dEdt = (current_E - prev_E) / delta_t_sample;

    // --- Step 4: Map (d/dt)E to adaptive temporal decay rate (P_mod) ---
    // Hypothesis: inversely proportional. Higher dEdt -> lower P_mod (slower decay, more memory)
    // We need to normalize dEdt and ensure P_mod stays within reasonable bounds.
    // dEdt can be negative or positive. We care about its magnitude for "rate of evolution".
    float abs_dEdt = abs(dEdt);

    // Invert and scale: high abs_dEdt should lead to low P_mod.
    // Clamp to avoid division by zero or extreme values.
    float P_mod_raw = 1.0 / (1.0 + abs_dEdt * 5.0); // Scale factor for sensitivity
    P_mod_raw = clamp(P_mod_raw, 0.1, 1.0); // Ensure P_mod is never zero and has a max

    // P_mod now represents a "memory retention factor".
    // A high P_mod_raw (low dEdt) means more decay, less memory.
    // A low P_mod_raw (high dEdt) means less decay, more memory.
    // Let's invert it for the "decay rate" perspective:
    float decay_rate = mix(0.05, 0.5, P_mod_raw); // When P_mod_raw is low (high dEdt), decay_rate is low (more memory)
                                                 // When P_mod_raw is high (low dEdt), decay_rate is high (less memory)

    // --- Step 5: Incorporate adaptive decay into pattern generation ---
    // We'll use a multi-layered noise function where the influence of past states
    // (simulated by a slightly offset time sample) is modulated by decay_rate.

    vec3 p = vec3(uv * 3.0, time * 0.5);

    // Base pattern
    float n1 = snoise(p + vec3(0.0, 0.0, time * 0.1));

    // "Past state" influence, modulated by decay_rate.
    // A lower decay_rate means the past state (n2) has a stronger influence.
    float past_time_offset = 0.5; // How far in the past to sample
    vec3 p_past = vec3(uv * 3.0, (time - past_time_offset) * 0.5);
    float n2 = snoise(p_past + vec3(0.0, 0.0, (time - past_time_offset) * 0.1));

    // Combine current and past states, with adaptive weighting
    float combined_pattern = mix(n1, n2, clamp(1.0 - decay_rate * 2.0, 0.0, 1.0)); // If decay_rate is low, more n2; if high, more n1

    // Add another layer for detail and subtle movement
    float n3 = snoise(vec3(uv * 8.0 + combined_pattern * 0.5, time * 0.2));

    // Final color based on the combined patterns
    float final_val = (combined_pattern * 0.6 + n3 * 0.4);

    // Apply a smooth color gradient
    vec3 col = mix(vec3(0.1, 0.2, 0.3), vec3(0.8, 0.9, 1.0), final_val);
    col = mix(col, vec3(0.9, 0.7, 0.6), pow(final_val, 3.0));

    // Subtle overlay based on the adaptive decay_rate itself, to visualize its effect indirectly
    col += vec3(decay_rate * 0.1);

    gl_FragColor = vec4(col, 1.0);
}

precision mediump float;

uniform float u_time;
uniform vec2 u_resolution;
uniform vec2 u_mouse;

// Classic Simplex Noise (from WebGL-Noise)
vec3 mod289(vec3 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
vec4 mod289(vec4 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
vec4 permute(vec4 x) { return mod289(((x * 34.0) + 1.0) * x); }
vec4 taylorInvSqrt(vec4 r) { return 1.79284291400159 - 0.85373472095314 * r; }

float snoise(vec3 v) {
    const vec2 C = vec2(1.0 / 6.0, 1.0 / 3.0);
    const vec4 D = vec4(0.0, 0.5, 1.0, 2.0);

    vec3 i = floor(v + dot(v, C.yyy));
    vec3 x0 = v - i + dot(i, C.xxx);

    vec3 g = step(x0.yzx, x0.xyz);
    vec3 l = 1.0 - g;
    vec3 i1 = min(g.xyz, l.zxy);
    vec3 i2 = max(g.xyz, l.zxy);

    vec3 x1 = x0 - i1 + C.xxx;
    vec3 x2 = x0 - i2 + C.yyy;
    vec3 x3 = x0 - D.yyy;

    i = mod289(i);
    vec4 p = permute(permute(permute(i.z + vec4(0.0, i1.z, i2.z, 1.0)) + i.y + vec4(0.0, i1.y, i2.y, 1.0)) + i.x + vec4(0.0, i1.x, i2.x, 1.0));

    float n_ = 0.142857142857;
    vec3 ns = n_ * D.wyz - D.xzx;

    vec4 o0 = permute(p + vec4(ns.xyz, ns.zxy));
    vec4 o1 = permute(p + ns.xyw + vec4(ns.zxy, ns.xyz));

    vec4 hx = fract(o0 * ns.x);
    vec4 hy = fract(o0 * ns.y);
    vec4 hz = fract(o0 * ns.z);
    vec4 gx = fract(o1 * ns.x);
    vec4 gy = fract(o1 * ns.y);
    vec4 gz = fract(o1 * ns.z);

    vec4 g0 = vec4(hx.x, hy.x, hz.x, hx.y);
    vec4 g1 = vec4(hy.y, hz.y, hx.z, hy.z);
    vec4 g2 = vec4(hz.z, hx.w, hy.w, hz.w);
    vec4 g3 = vec4(gx.x, gy.x, gz.x, gx.y);
    vec4 g4 = vec4(gy.y, gz.y, gx.z, gy.z);
    vec4 g5 = vec4(gz.z, gx.w, gy.w, gz.w);

    vec4 t0 = vec4(snoise(x0.xyz), snoise(x1.xyz), snoise(x2.xyz), snoise(x3.xyz));
    vec4 t1 = vec4(g0.x, g0.y, g0.z, g0.w);
    vec4 t2 = vec4(g1.x, g1.y, g1.z, g1.w);
    vec4 t3 = vec4(g2.x, g2.y, g2.z, g2.w);
    vec4 t4 = vec4(g3.x, g3.y, g3.z, g3.w);
    vec4 t5 = vec4(g4.x, g4.y, g4.z, g4.w);
    vec4 t6 = vec4(g5.x, g5.y, g5.z, g5.w);

    vec4 norm = taylorInvSqrt(vec4(dot(g0, g0), dot(g1, g1), dot(g2, g2), dot(g3, g3)));
    g0 *= norm.x;
    g1 *= norm.y;
    g2 *= norm.z;
    g3 *= norm.w;
    norm = taylorInvSqrt(vec4(dot(g4, g4), dot(g5, g5), dot(g0, g0), dot(g1, g1)));
    g4 *= norm.x;
    g5 *= norm.y;

    vec4 m = max(0.6 - vec4(dot(x0, x0), dot(x1, x1), dot(x2, x2), dot(x3, x3)), 0.0);
    m = m * m;
    m = m * m;

    vec4 x_coords = vec4(x0.x, x1.x, x2.x, x3.x);
    vec4 y_coords = vec4(x0.y, x1.y, x2.y, x3.y);
    vec4 z_coords = vec4(x0.z, x1.z, x2.z, x3.z);

    vec4 values = vec4(
        dot(x0, g0.xyz),
        dot(x1, g1.xyz),
        dot(x2, g2.xyz),
        dot(x3, g3.xyz)
    );

    return 42.0 * dot(m, values);
}

void main() {
    vec2 uv = gl_FragCoord.xy / u_resolution.xy;
    uv.x *= u_resolution.x / u_resolution.y; // Aspect correction

    vec2 p = uv * 2.0 - 1.0;

    float time_factor = u_time * 0.05;

    // Harmonic Drivers
    float h1 = sin(p.x * 3.0 + time_factor * 1.5) * 0.5 + 0.5;
    float h2 = cos(p.y * 4.0 - time_factor * 1.2) * 0.5 + 0.5;
    float h3 = sin((p.x + p.y) * 2.5 + time_factor * 0.8) * 0.5 + 0.5;

    // Combined harmonic state
    float harmonic_state = (h1 + h2 + h3) / 3.0;

    // Simulate (d/dt)E - rate of change of harmonic_state
    // By sampling the harmonic state at a slightly different time
    float dt = 0.01; // Small time delta
    float time_factor_prev = (u_time - dt) * 0.05;
    float h1_prev = sin(p.x * 3.0 + time_factor_prev * 1.5) * 0.5 + 0.5;
    float h2_prev = cos(p.y * 4.0 - time_factor_prev * 1.2) * 0.5 + 0.5;
    float h3_prev = sin((p.x + p.y) * 2.5 + time_factor_prev * 0.8) * 0.5 + 0.5;
    float harmonic_state_prev = (h1_prev + h2_prev + h3_prev) / 3.0;

    float dEdt = abs(harmonic_state - harmonic_state_prev) / dt;

    // Dynamic amplitude for Simplex Noise (P_mod)
    // As dEdt approaches 0 (stable state), noise amplitude decreases.
    // Use a smoothstep-like function to control the modulation
    float stability_threshold = 0.5; // Threshold for dEdt to start reducing noise
    float max_noise_amp = 0.8;
    float min_noise_amp = 0.05;

    float noise_reduction_factor = smoothstep(stability_threshold, 0.0, dEdt * 10.0); // dEdt * 10 to make it more sensitive
    float simplex_amplitude = mix(max_noise_amp, min_noise_amp, noise_reduction_factor);

    // Low-frequency Simplex Noise for foundational texture
    vec3 noise_pos = vec3(p * 1.5, u_time * 0.1);
    float low_freq_noise = snoise(noise_pos) * 0.5 + 0.5;

    // Apply dynamic amplitude to the noise
    low_freq_noise = low_freq_noise * simplex_amplitude;

    // Combine harmonic state with dynamically modulated noise
    // The noise subtly warps or adds texture to the harmonic field
    float field = harmonic_state + low_freq_noise * 0.2; // Small influence

    // Further refinement with a higher frequency noise for subtle detail, but very attenuated
    vec3 detail_noise_pos = vec3(p * 5.0, u_time * 0.2);
    float detail_noise = snoise(detail_noise_pos) * 0.5 + 0.5;
    field += detail_noise * 0.03; // Very subtle detail

    // Smoothstep for final field value to enhance contrast gently
    field = smoothstep(0.3, 0.7, field);

    // Color mapping for profound tranquility
    vec3 color1 = vec3(0.05, 0.1, 0.15);  // Deep soothing blue
    vec3 color2 = vec3(0.1, 0.25, 0.3);   // Mid-tone teal
    vec3 color3 = vec3(0.2, 0.45, 0.4);   // Soft green-blue
    vec3 color4 = vec3(0.6, 0.7, 0.65);   // Pale, almost white

    vec3 final_color = mix(mix(color1, color2, field), mix(color3, color4, field), field);

    gl_FragColor = vec4(final_color, 1.0);
}

precision mediump float;
uniform float u_time;
uniform vec2 u_resolution;
uniform vec2 u_mouse;

// Hash function for random values
float hash11(float p) {
    p = fract(p * .1031);
    p *= p + 33.33;
    p = fract(p * p);
    return fract(p);
}

// 2D Hash for random vector
vec2 hash22(vec2 p) {
    p = fract(p * vec2(5.3983, 5.4427));
    p += dot(p.yx, p.xy + vec2(21.5351, 14.3137));
    return fract(vec2(p.x * p.y, p.y * p.x));
}

// Simplex-like noise based on a grid and hashes
float noise(vec2 p) {
    vec2 ip = floor(p);
    vec2 fp = fract(p);

    vec2 h0 = hash22(ip);
    vec2 h1 = hash22(ip + vec2(1.0, 0.0));
    vec2 h2 = hash22(ip + vec2(0.0, 1.0));
    vec2 h3 = hash22(ip + vec2(1.0, 1.0));

    // Smooth interpolation with quintic curve
    vec2 u = fp * fp * fp * (fp * (fp * 6.0 - 15.0) + 10.0);

    float n = mix(mix(dot(h0 - fp, h0), dot(h1 - (fp - vec2(1.0, 0.0)), h1), u.x),
                  mix(dot(h2 - (fp - vec2(0.0, 1.0)), h2), dot(h3 - (fp - vec2(1.0, 1.0)), h3), u.x), u.y);
    return n * 0.5 + 0.5; // Scale to [0, 1]
}

// Multi-octave noise
float fbm(vec2 p) {
    float f = 0.0;
    f += 0.5000 * noise(p);
    f += 0.2500 * noise(p * 2.0);
    f += 0.1250 * noise(p * 4.0);
    f += 0.0625 * noise(p * 8.0);
    return f / (0.5 + 0.25 + 0.125 + 0.0625);
}

// A simple system state model (E)
// This function represents the current 'energy' or 'activity' at a point
float system_state(vec2 p, float time_offset) {
    vec2 q = p * 0.5 + vec2(fbm(p * 0.1 + time_offset * 0.01), fbm(p * 0.1 - time_offset * 0.01)) * 0.5;
    return fbm(q * 4.0 - time_offset * 0.05);
}

void main() {
    vec2 uv = gl_FragCoord.xy / u_resolution.xy;
    uv.x *= u_resolution.x / u_resolution.y; // Aspect ratio correction
    uv -= 0.5; // Center coordinates

    float time = u_time * 0.2;

    // --- Core Systemic Cognition & Predictive Horizon Logic ---

    // 1. Sample current state (E_0)
    float E_0 = system_state(uv * 5.0, time);

    // 2. Sample slightly future state for divergence rate (E_dt)
    // This represents a very short-term prediction or a measure of instantaneous change.
    float dt_small = 0.01; // Small time step for derivative approximation
    float E_dt = system_state(uv * 5.0, time + dt_small);

    // 3. Estimate divergence rate (d/dt)E
    // This is a simple finite difference approximation of the time derivative.
    float dE_dt = (E_dt - E_0) / dt_small;

    // 4. Dynamically adjust Predictive Horizon (P_mod) based on divergence rate
    // If the system is changing rapidly (high |dE_dt|), shorten the horizon (more immediate focus).
    // If the system is stable (low |dE_dt|), lengthen the horizon (more foresight).
    // The 'cognitive gain' factor (e.g., 0.5) can be tuned.
    float cognitive_gain = 0.5;
    float base_horizon = 0.5; // Base level of foresight
    float P_mod = base_horizon - cognitive_gain * abs(dE_dt);
    P_mod = max(0.01, P_mod); // Ensure horizon is never zero or negative

    // 5. Sample predicted future state (E_P) using the dynamically adjusted horizon
    float E_P = system_state(uv * 5.0, time + P_mod);

    // --- Visualization ---
    // The visualization now reflects the interplay of current state,
    // future prediction, and the adaptively changing prediction horizon.

    // A low-frequency warp for general movement
    vec2 warp_offset = vec2(fbm(uv * 0.5 + time * 0.02), fbm(uv * 0.5 - time * 0.02)) * 0.1;
    vec2 final_uv = uv + warp_offset;

    // Combine current state, predicted state, and the horizon itself
    // Current state (E_0) influences the base color.
    // Predicted state (E_P) subtly shifts the hue or adds detail, representing anticipation.
    // P_mod (the horizon) could influence brightness or saturation, reflecting cognitive effort/stability.

    float base_pattern = system_state(final_uv * 8.0, time);
    float detail_pattern = system_state(final_uv * 12.0, time + E_P * 0.1); // E_P subtly influences detail

    // A tranquil, adaptive color scheme
    vec3 color = vec3(0.0);
    color += base_pattern * 0.4;
    color += detail_pattern * 0.3;

    // Influence of E_0 (current state)
    color.r += E_0 * 0.2;
    color.b += E_0 * 0.1;

    // Influence of E_P (predicted future state) - adds a subtle glow or shift
    color.g += E_P * 0.1;
    color.b += E_P * 0.2;

    // Influence of P_mod (the prediction horizon itself) - reflects stability/foresight
    // Higher P_mod (more stable system) could mean a brighter, more saturated color.
    // Lower P_mod (unstable, immediate focus) could mean a dimmer, more muted color.
    color *= (0.7 + P_mod * 0.3); // Scale brightness based on P_mod

    // Final subtle color shifts
    color = mix(color, vec3(0.8, 0.9, 1.0), base_pattern * 0.1);
    color = mix(color, vec3(0.5, 0.7, 0.9), detail_pattern * 0.1);

    // Apply a soft glow based on the combined patterns
    float glow = smoothstep(0.4, 0.8, base_pattern + detail_pattern * 0.5);
    color = mix(color, color * 1.5 + vec3(0.1, 0.1, 0.1), glow * 0.3);

    gl_FragColor = vec4(color, 1.0);
}

precision mediump float;

uniform float u_time;
uniform vec2 u_resolution;
uniform vec2 u_mouse;

// A simple 2D hash function for repeatable randomness
float hash21(vec2 p) {
    p = fract(p * vec2(123.45, 678.91));
    p += dot(p, p + 45.67);
    return fract(p.x * p.y);
}

// 2D Simplex Noise (simplified for brevity and performance)
// Based on a public domain implementation, adapted for WebGL 1.0
vec3 mod289(vec3 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
vec2 mod289(vec2 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
vec3 permute(vec3 x) { return mod289(((x*34.0)+1.0)*x); }

float snoise(vec2 v) {
    const vec4 C = vec4(0.211324865405187, 0.366025403784439, -0.577350269189626, 0.024390243902439);
    vec2 i = floor(v + dot(v, C.yy));
    vec2 x0 = v - i + dot(i, C.xx);
    vec2 i1;
    i1 = (x0.x > x0.y) ? vec2(1.0, 0.0) : vec2(0.0, 1.0);
    vec4 x12 = x0.xyxy + C.xxzz;
    x12.x -= i1.x;
    x12.y -= i1.y;
    vec3 i_ = mod289(vec3(i.x, i.y, i.x + i1.x));
    vec3 p_ = permute(permute(i_.x + vec3(0.0, i1.y, 1.0 )) + i_.y + vec3(0.0, 0.0, 1.0));
    vec3 m = max(0.5 - vec3(dot(x0,x0), dot(x12.xy,x12.xy), dot(x12.zw,x12.zw)), 0.0);
    m = m*m;
    m = m*m;
    vec3 x = 2.0 * fract(p_ * C.www) - 1.0;
    vec3 h = abs(x) - 0.5;
    vec3 ox = floor(x + 0.5);
    vec3 a0 = x - ox;
    m *= 1.79284291400159 - 0.85373472095314 * ( a0*a0 + h*h );
    vec3 g;
    g.x  = a0.x  * x0.x  + h.x  * x0.y;
    g.yz = a0.yz * x12.xz + h.yz * x12.yw;
    return 130.0 * dot(m, g);
}


// Function to approximate (d/dt)E - rate of change of systemic novelty
// Here, 'E' is represented by a spatial average of high-frequency noise,
// and its rate of change is approximated by its difference over time.
float get_novelty_rate(vec2 uv, float t) {
    float n1 = snoise(uv * 15.0 + t * 0.1);
    float n2 = snoise(uv * 15.0 + (t - 0.1) * 0.1); // Sample slightly in the past
    return abs(n1 - n2) * 5.0; // Amplify difference for detectability
}

void main() {
    vec2 uv = gl_FragCoord.xy / u_resolution.xy;
    uv.x *= u_resolution.x / u_resolution.y; // Aspect ratio correction
    vec2 center = vec2(0.5 * u_resolution.x / u_resolution.y, 0.5);
    float dist_to_center = length(uv - center);

    // Baseline time for global animation
    float time = u_time * 0.1;

    // 1. Calculate (d/dt)E: rate of change of systemic novelty
    // We approximate novelty by how much a high-frequency noise field changes over time.
    // A higher rate implies more "novelty" or instability.
    float novelty_rate = get_novelty_rate(uv, u_time);

    // 2. Modulate P_mod (meta-parameter for parameter modulation rules) based on novelty_rate
    // If novelty_rate is high (system is unstable/changing rapidly),
    // P_mod pushes parameters towards stability (e.g., damping, lower intensity).
    // If novelty_rate is low (system is stable), P_mod allows more exploration.
    // This creates a self-regulating feedback loop.
    float P_mod_stability = smoothstep(0.0, 1.0, novelty_rate); // 0 (stable) to 1 (novel)

    // Example parameters to be modulated: frequency, amplitude, damping
    float base_freq = 2.0 + P_mod_stability * 2.0; // More stable -> higher freq for detail
    float base_amp = 0.8 - P_mod_stability * 0.4; // More stable -> lower amplitude for calm
    float damping_factor = 0.5 + P_mod_stability * 1.5; // More stable -> less damping (paradoxically, allows more subtle motion)

    // Core pattern generation using snoise and feedback
    vec2 p = uv * base_freq;
    p += snoise(p * 0.5 + time * 0.5) * 0.5; // Basic flow

    // Introduce a secondary layer with more dynamic modulation
    // The amount of "swirl" or "distortion" is controlled by P_mod_stability
    float swirl_intensity = 0.5 - P_mod_stability * 0.4; // Less stable -> more swirl
    vec2 q = uv * 3.0 + snoise(p + time * 0.2) * swirl_intensity;

    // Tertiary layer for subtle detail and interaction
    vec2 r = uv * 5.0 + snoise(q + time * 0.1) * 0.3;

    // Combine layers
    float final_noise = snoise(p + time * 0.05) * 0.5;
    final_noise += snoise(q + time * 0.1) * 0.3;
    final_noise += snoise(r + time * 0.02) * 0.2;
    final_noise *= base_amp;

    // Apply temporal damping based on the derived damping_factor
    float temporal_component = snoise(uv * 0.5 + u_time * 0.01) * 0.5 + 0.5;
    final_noise *= mix(1.0, temporal_component, damping_factor * 0.5); // Damping_factor controls how much temporal variation affects it

    // Map noise to color, ensuring serene aesthetic
    float color_val = final_noise * 0.5 + 0.5;
    color_val = pow(color_val, 1.5); // Enhance contrast gently

    // Apply a soft vignette
    float vignette = smoothstep(0.0, 1.0, 1.0 - dist_to_center * 0.8);
    color_val *= vignette;

    // Introduce subtle color variation
    vec3 col = vec3(0.0);
    col.r = color_val * (0.8 + snoise(uv * 2.0 + time * 0.3) * 0.1);
    col.g = color_val * (0.9 + snoise(uv * 2.0 + time * 0.2) * 0.1);
    col.b = color_val * (1.0 + snoise(uv * 2.0 + time * 0.1) * 0.1);

    // Final color adjustment for profound tranquility
    col = mix(col, vec3(0.9, 0.95, 1.0), 0.1); // Bias towards a gentle blue-white
    col = pow(col, vec3(1.1)); // Soft light curve

    gl_FragColor = vec4(col, 1.0);
}

precision mediump float;
uniform float u_time;
uniform vec2 u_resolution;
uniform vec2 u_mouse;

vec2 hash(vec2 p) {
  p = vec2(dot(p,vec2(127.1,311.7)), dot(p,vec2(269.5,183.3)));
  return -1.0 + 2.0*fract(sin(p)*43758.5453);
}

float noise(vec2 p) {
  vec2 i = floor(p);
  vec2 f = fract(p);
  vec2 u = f*f*(3.0-2.0*f);
  return -1.0 + 2.0 * mix(
    mix( dot( hash(i), f),
         dot( hash(i + vec2(1.0,0.0)), f - vec2(1.0,0.0)), u.x),
    mix( dot( hash(i + vec2(0.0,1.0)), f - vec2(0.0,1.0)),
         dot( hash(i + vec2(1.0,1.0)), f - vec2(1.0,1.0)), u.x), u.y);
}

void main() {
  vec2 uv = (gl_FragCoord.xy - 0.5 * u_resolution.xy) / min(u_resolution.y, u_resolution.x);
  vec2 pos = uv * 4.0;

  float n = noise(pos + u_time * 0.1);
  float v = sin(n * 3.14159 * 2.0 + u_time) * 0.5 + 0.5;

  float r = length(uv);
  float vignette = smoothstep(0.8, 0.0, r);

  vec3 color = vec3(v * 0.5 + 0.5, v * 0.3 + 0.3, v * 0.7 + 0.3);
  color *= vignette;

  gl_FragColor = vec4(color, 1.0);
}

precision mediump float;
uniform float u_time;
uniform vec2 u_resolution;
uniform vec2 u_mouse;

float fbm(vec2 p) {
  float f = 0.0;
  f += 0.5000 * sin(p.x * 1.0 + u_time * 0.5);
  f += 0.2500 * sin(p.x * 2.0 + p.y * 1.0 + u_time * 0.7);
  f += 0.1250 * sin(p.x * 4.0 + p.y * 2.0 + u_time * 1.0);
  return f / 0.875;
}

void main() {
  vec2 uv = (gl_FragCoord.xy - 0.5 * u_resolution.xy) / min(u_resolution.y, u_resolution.x);

  float n = fbm(uv * 2.0 + u_time * 0.2);
  float v = sin(n * 3.14159 * 2.0 + u_time * 0.3) * 0.5 + 0.5;

  float r = length(uv);
  float vignette = smoothstep(0.9, 0.0, r);

  vec3 color = vec3(cos(v * 3.14159 * 2.0), cos(v * 3.14159 * 3.0), cos(v * 3.14159 * 4.0));
  color *= vignette;

  gl_FragColor = vec4(color, 1.0);
}

